const mainWidth = $input.item.json.metaMain.size.width;
const mainHeight = $input.item.json.metaMain.size.height;

const logoWidth = $input.item.json.metaLogo.size.width;
const logoHeight = $input.item.json.metaLogo.size.height;

// Position logo at bottom-right corner with 20px margin
const posX = mainWidth - logoWidth ;
const posY = mainHeight - logoHeight ;

$input.item.json.position = { x: posX, y: posY };

return $input.item;

const rows = $("Get row(s) in sheet").all();

return rows.map((row) => {

  const dateStr = row.json["Scheduled Date"];
  const timeStr = row.json["Time"];

  if (!dateStr || !timeStr) {
    return { json: row.json };
  }

  // Treat sheet time as Australia time
  const scheduled = new Date(
    new Date(`${dateStr} ${timeStr}`)
      .toLocaleString("en-US", { timeZone: "Australia/Sydney" })
  );

  const now = new Date();

  const diffMinutes = (scheduled - now) / (1000 * 60);

  return {
    json: {
      ...row.json,
      scheduledUTC: scheduled.toISOString(),
      timeDifference: diffMinutes
    }
  };
});

// Safe unicode bold maps
const normal = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789";
const bold   = "𝗮𝗯𝗰𝗱𝗲𝗳𝗴𝗵𝗶𝗷𝗸𝗹𝗺𝗻𝗼𝗽𝗾𝗿𝘀𝘁𝘂𝘃𝘄𝘅𝘆𝘇" +
               "𝗔𝗕𝗖𝗗𝗘𝗙𝗚𝗛𝗜𝗝𝗞𝗟𝗠𝗡𝗢𝗣𝗤𝗥𝗦𝗧𝗨𝗩𝗪𝗫𝗬𝗭" +
               "𝟬𝟭𝟮𝟯𝟰𝟱𝟲𝟕𝟴𝟵";

// Convert a-zA-Z0-9 only
function safeBoldWord(word) {
  return word.split('').map(ch => {
    const idx = normal.indexOf(ch);
    return idx !== -1 ? bold[idx] : ch;
  }).join('');
}

// Replace **TEXT** only when it's clean ASCII text
let text =$input.first().json.output ;

// Regex to catch **bold text**
text = text.replace(/\*\*(.*?)\*\*/g, (match, inside) => {

  // If inside contains emoji/symbols → DON'T bold
  if (/[^a-zA-Z0-9 ]/.test(inside)) {
    return inside; // return without **
  }

  return safeBoldWord(inside);
});

return { text };

